import{_ as t,o as i,c as a,ag as n}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Facturation et abonnements","description":"","frontmatter":{},"headers":[],"relativePath":"fr/settings/billing.md","filePath":"fr/settings/billing.md"}'),r={name:"fr/settings/billing.md"};function l(s,e,o,u,d,c){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="facturation-et-abonnements" tabindex="-1">Facturation et abonnements <a class="header-anchor" href="#facturation-et-abonnements" aria-label="Permalink to &quot;Facturation et abonnements&quot;">​</a></h1><p>Gerez votre abonnement MyCompanyDesk, consultez votre utilisation et mettez a niveau votre plan.</p><h2 id="abonnements" tabindex="-1">Abonnements <a class="header-anchor" href="#abonnements" aria-label="Permalink to &quot;Abonnements&quot;">​</a></h2><p>MyCompanyDesk propose trois plans :</p><h3 id="gratuit" tabindex="-1">Gratuit <a class="header-anchor" href="#gratuit" aria-label="Permalink to &quot;Gratuit&quot;">​</a></h3><p>Commencez sans frais :</p><ul><li>Factures et clients limites</li><li>Suivi des depenses basique</li><li>Rapports basiques</li><li>1 utilisateur</li><li>Support communautaire</li></ul><h3 id="pro" tabindex="-1">Pro <a class="header-anchor" href="#pro" aria-label="Permalink to &quot;Pro&quot;">​</a></h3><p>Pour les entreprises en croissance :</p><ul><li>Factures et clients illimites</li><li>Suivi complet des depenses avec numerisation de recus</li><li>Suggestions IA</li><li>Image de marque PDF personnalisee</li><li>Export CSV</li><li>Jusqu&#39;a 5 membres d&#39;equipe</li><li>Support par e-mail</li></ul><h3 id="business" tabindex="-1">Business <a class="header-anchor" href="#business" aria-label="Permalink to &quot;Business&quot;">​</a></h3><p>Pour les equipes et les operations en expansion :</p><ul><li>Tout ce qui est inclus dans Pro</li><li>Membres d&#39;equipe illimites</li><li>Acces API</li><li>Support prioritaire</li><li>Integrations avancees</li></ul><p>Les plans sont disponibles en intervalles de facturation <strong>mensuelle</strong> et <strong>annuelle</strong>. Les plans annuels incluent une remise.</p><h2 id="gerer-votre-abonnement" tabindex="-1">Gerer votre abonnement <a class="header-anchor" href="#gerer-votre-abonnement" aria-label="Permalink to &quot;Gerer votre abonnement&quot;">​</a></h2><h3 id="mettre-a-niveau" tabindex="-1">Mettre a niveau <a class="header-anchor" href="#mettre-a-niveau" aria-label="Permalink to &quot;Mettre a niveau&quot;">​</a></h3><ol><li>Allez dans <strong>Parametres &gt; Facturation</strong></li><li>Cliquez sur <strong>Mettre a niveau</strong> sur le plan souhaite</li><li>Completez le paiement via Stripe</li><li>Les fonctionnalites sont activees immediatement</li></ol><h3 id="reduire-le-plan" tabindex="-1">Reduire le plan <a class="header-anchor" href="#reduire-le-plan" aria-label="Permalink to &quot;Reduire le plan&quot;">​</a></h3><ol><li>Allez dans <strong>Parametres &gt; Facturation</strong></li><li>Cliquez sur <strong>Changer de plan</strong></li><li>Selectionnez le plan inferieur</li><li>Les changements prennent effet a la fin de la periode de facturation en cours</li></ol><h3 id="annuler" tabindex="-1">Annuler <a class="header-anchor" href="#annuler" aria-label="Permalink to &quot;Annuler&quot;">​</a></h3><ol><li>Allez dans <strong>Parametres &gt; Facturation</strong></li><li>Cliquez sur <strong>Gerer l&#39;abonnement</strong> pour ouvrir le portail de facturation Stripe</li><li>Annulez votre abonnement</li><li>Vous conservez l&#39;acces jusqu&#39;a la fin de la periode payee</li></ol><h2 id="suivi-de-l-utilisation" tabindex="-1">Suivi de l&#39;utilisation <a class="header-anchor" href="#suivi-de-l-utilisation" aria-label="Permalink to &quot;Suivi de l&#39;utilisation&quot;">​</a></h2><p>Consultez votre utilisation actuelle sur la page de facturation :</p><ul><li><strong>Factures creees</strong> ce mois-ci</li><li><strong>Clients</strong> dans votre espace de travail</li><li><strong>Membres de l&#39;equipe</strong> actifs</li><li><strong>Appels API</strong> (plan Business)</li></ul><p>L&#39;utilisation est reinitialise mensuellement. Si vous approchez d&#39;une limite, vous verrez une notification suggerant une mise a niveau.</p><h2 id="methodes-de-paiement" tabindex="-1">Methodes de paiement <a class="header-anchor" href="#methodes-de-paiement" aria-label="Permalink to &quot;Methodes de paiement&quot;">​</a></h2><p>Les paiements sont traites de maniere securisee via <strong>Stripe</strong>. Methodes acceptees :</p><ul><li>Carte de credit (Visa, Mastercard, Amex)</li><li>Carte de debit</li><li>Prelevement SEPA (UE)</li></ul><p>Gerez votre methode de paiement dans le portail de facturation Stripe.</p><h2 id="portail-de-facturation" tabindex="-1">Portail de facturation <a class="header-anchor" href="#portail-de-facturation" aria-label="Permalink to &quot;Portail de facturation&quot;">​</a></h2><p>Cliquez sur <strong>Gerer l&#39;abonnement</strong> pour acceder au portail de facturation Stripe ou vous pouvez :</p><ul><li>Mettre a jour votre methode de paiement</li><li>Consulter l&#39;historique des factures</li><li>Telecharger les recus</li><li>Modifier l&#39;adresse de facturation</li></ul><h2 id="droits-d-acces-aux-fonctionnalites" tabindex="-1">Droits d&#39;acces aux fonctionnalites <a class="header-anchor" href="#droits-d-acces-aux-fonctionnalites" aria-label="Permalink to &quot;Droits d&#39;acces aux fonctionnalites&quot;">​</a></h2><p>Certaines fonctionnalites sont reservees a certains plans :</p><table tabindex="0"><thead><tr><th>Fonctionnalite</th><th>Gratuit</th><th>Pro</th><th>Business</th></tr></thead><tbody><tr><td>Image de marque personnalisee</td><td>-</td><td>Oui</td><td>Oui</td></tr><tr><td>Export CSV</td><td>-</td><td>Oui</td><td>Oui</td></tr><tr><td>Numerisation de recus</td><td>-</td><td>Oui</td><td>Oui</td></tr><tr><td>Suggestions IA</td><td>-</td><td>Oui</td><td>Oui</td></tr><tr><td>Verification de texte</td><td>-</td><td>Oui</td><td>Oui</td></tr><tr><td>Acces API</td><td>-</td><td>-</td><td>Oui</td></tr></tbody></table><p>Tenter d&#39;utiliser une fonctionnalite reservee sur un plan inferieur affiche une invitation a mettre a niveau.</p>',36)])])}const h=t(r,[["render",l]]);export{m as __pageData,h as default};
